// optional import of sdk modules
import { execution } from '@dynatrace-sdk/automation-utils';
import { workflowsClient } from "@dynatrace-sdk/client-automation";

export default async function ({ executionId , action_execution_id }) {
  // your code goes here
  // e.g. get the current execution
  const { input } = await fetch(`/platform/automation/v1/executions/${executionId}`).then((res) => res.json());

  const data = await workflowsClient.deleteWorkflow({
    id: input.workflowid,
  });
  return data;
}
